parameters.jsCode:
const rawContent = $input.first().json.choices[0].message.content;
const cleanContent = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const parsed = JSON.parse(cleanContent);
return [{ json: parsed }];

const rawContent = $input.first().json.choices[0].message.content;
const cleanContent = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const scoring = JSON.parse(cleanContent);
const profile = $('Code').first().json;

return [{
  json: {
    nom: profile.nom,
    email: profile.email,
    telephone: "'" + profile.telephone,
    nombre_stages: profile.nombre_stages,
    experience_pertinente_mois: scoring.experience_pertinente_mois,
    competences: profile.competences.join(", "),
    formation: profile.formation,
    projets_academiques: profile.projets_academiques.join(" | "),
    score_matching: scoring.score_matching,
    statut: scoring.statut,
    competences_matchees: scoring.competences_matchees.join(", "),
    competences_manquantes: scoring.competences_manquantes.join(", "),
    projets_pertinents: scoring.projets_pertinents.join(", "),
    recommandation: scoring.recommandation,
    date_analyse: new Date().toISOString()
  }
}];

